3	const OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survives = (count: number): boolean => count === 2 || count === 3;
15	const reproduces = (count: number): boolean => count === 3;
16	
17	export function nextGeneration(cells: Cell[]): Cell[] {
18	  const live = new Set(cells.map(keyOf));
19	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
20	
21	  for (const cell of cells) {
22	    for (const neighbor of neighborsOf(cell)) {
23	      const k = keyOf(neighbor);
24	      const entry = neighborCounts.get(k) ?? { cell: neighbor, count: 0 };
25	      entry.count++;
26	      neighborCounts.set(k, entry);
27	    }
28	  }
29	
30	  return Array.from(neighborCounts).flatMap(([k, { cell, count }]) =>
31	    (live.has(k) ? survives(count) : reproduces(count)) ? [cell] : []
32	  );
33	}
