1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single live cell (underpopulation: 0 neighbors)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent cells (underpopulation: each has 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("keeps a 2x2 block alive unchanged (each cell has 3 neighbors)", () => {
15	    const block: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("creates a new cell where a dead cell has exactly 3 live neighbors (reproduction)", () => {
20	    // L-shape: (0,0),(1,0),(0,1) — dead cell (1,1) has 3 live neighbors, becomes alive.
21	    // All three live cells also have 2 neighbors each, so they survive too.
22	    const input: Array<[number, number]> = [[0, 0], [1, 0], [0, 1]];
23	    const expected: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
24	    expect(nextGeneration(input).sort()).toEqual(expected.sort());
25	  });
26	  it("kills a cell with more than 3 live neighbors (overpopulation)", () => {
27	    // ###    Center (1,1) has 6 live neighbors (top row + bottom row corners + middles)
28	    // .#.    so it dies from overpopulation.
29	    // ###
30	    const input: Array<[number, number]> = [
31	      [0, 0], [1, 0], [2, 0],
32	      [1, 1],
33	      [0, 2], [1, 2], [2, 2],
34	    ];
35	    const result = nextGeneration(input);
36	    expect(result).not.toContainEqual([1, 1]);
37	  });
38	  it("transforms a vertical blinker into a horizontal blinker", () => {
39	    const vertical: Array<[number, number]> = [[0, 0], [0, 1], [0, 2]];
40	    const horizontal: Array<[number, number]> = [[-1, 1], [0, 1], [1, 1]];
41	    expect(nextGeneration(vertical).sort()).toEqual(horizontal.sort());
42	  });
43	});
