export function nextGeneration(cells: Cell[]): Cell[] {
  const live = new Set(cells.map(keyOf));
  const allNeighbors = cells.flatMap(neighborsOf);
  const candidates = new Map(allNeighbors.map((cell) => [keyOf(cell), cell]));
  const counts = allNeighbors.reduce(
    (acc, n) => acc.set(keyOf(n), (acc.get(keyOf(n)) ?? 0) + 1),
    new Map<string, number>()
  );

  return Array.from(candidates).flatMap(([k, cell]) =>
    (live.has(k) ? survives(counts.get(k)!) : reproduces(counts.get(k)!)) ? [cell] : []
  );
}

